it("should compute base premium 175 G for 7 runes (7 x 25, no block)", () => {
  const scenario = {
    customer: { yearsWithMHPCO: 0 },
    steps: [
      {
        op: "quote" as const,
        items: Array.from({ length: 7 }, () => ({
          type: "rune",
          material: "magic",
          enchantment: 0,
          cursed: false,
        })),
      },
    ],
  };
  const result = processScenario(scenario);
  // base premium = 7 x 25 = 175 (no block: count is not exactly 3); first-insurance = 10% of 175 = 17.5; fee = 5; total = 197.5
  expect(result.results[0]).toEqual({ premium: 197.5 });
});
